const LANDSCAPES = ["l1","l2","l3","l4","l5","l6"];
const GENRES = ["All","Action","Sci-Fi","Thriller","Drama","Comedy","Horror","Anime","Documentary","Crime","Romance","Fantasy"];

// Set hero image
document.getElementById('heroImg').src = IMG_DATA['p1'];

// Genre strip
const genreStrip = document.getElementById('genreStrip');
GENRES.forEach((g,i)=>{
  const el = document.createElement('div');
  el.className='genre-tag'+(i===0?' active':'');
  el.textContent=g;
  el.onclick=()=>{document.querySelectorAll('.genre-tag').forEach(x=>x.classList.remove('active'));el.classList.add('active');toast('Genre: '+g)};
  genreStrip.appendChild(el);
});

let myList = new Set();
let progresses = {};
SHOWS.forEach(s=>{progresses[s.title]=Math.random()});

function makePortraitCard(show, opts={}){
  const el = document.createElement('div');
  el.className='card'+(opts.rank?' rank':'');
  const prog = progresses[show.title];
  if(opts.rank){
    el.innerHTML=`<div class="rank-num">${opts.rankNum}</div>
      <div class="rank-thumb">
        <img class="portrait" src="${IMG_DATA[show.img]}" alt="${show.title}" loading="lazy">
        <div class="card-overlay">
          <div class="card-title">${show.title}</div>
          <div class="card-actions">
            <div class="card-btn play" onclick="event.stopPropagation();toast('Playing ${show.title}')">&#9654;</div>
            <div class="card-btn" onclick="event.stopPropagation();toggleList(this,'${show.title}')">${myList.has(show.title)?'&#10003;':'+'}</div>
          </div>
        </div>
      </div>`;
  } else {
    const progBar = opts.progress?`<div class="progress-bar"><div class="progress-fill" style="width:${Math.round(prog*100)}%"></div></div>`:'';
    el.innerHTML=`<img class="portrait" src="${IMG_DATA[show.img]}" alt="${show.title}" loading="lazy">
      ${progBar}
      <div class="card-overlay">
        <div class="card-title">${show.title}</div>
        <div class="card-subtitle">${show.sub}</div>
        <div class="card-actions">
          <div class="card-btn play" onclick="event.stopPropagation();toast('Playing ${show.title}')">&#9654;</div>
          <div class="card-btn" onclick="event.stopPropagation();toggleList(this,'${show.title}')">${myList.has(show.title)?'&#10003;':'+'}</div>
          <div class="card-btn" onclick="event.stopPropagation();toast('Liked!')">&#128077;</div>
          <span class="card-match">${show.match}</span>
        </div>
      </div>`;
  }
  el.onclick=()=>openModal(SHOWS.indexOf(show));
  return el;
}

function makeLandCard(show, lImg){
  const el=document.createElement('div');
  el.className='card land';
  el.innerHTML=`<img class="landscape" src="${IMG_DATA[lImg]}" alt="${show.title}" loading="lazy">
    <div class="card-overlay">
      <div class="card-title">${show.title}</div>
      <div class="card-subtitle">${show.year} &bull; ${show.dur}</div>
      <div class="card-actions">
        <div class="card-btn play" onclick="event.stopPropagation();toast('Playing ${show.title}')">&#9654;</div>
        <div class="card-btn" onclick="event.stopPropagation();toggleList(this,'${show.title}')">${myList.has(show.title)?'&#10003;':'+'}</div>
        <span class="card-match">${show.match}</span>
      </div>
    </div>`;
  el.onclick=()=>openModal(SHOWS.indexOf(show));
  return el;
}

function populateRow(id, shows, opts={}){
  const row=document.getElementById(id);
  shows.forEach((show,i)=>{
    if(opts.landscape){
      row.appendChild(makeLandCard(show, LANDSCAPES[i%LANDSCAPES.length]));
    } else if(opts.ranked){
      row.appendChild(makePortraitCard(show,{rank:true,rankNum:i+1}));
    } else {
      row.appendChild(makePortraitCard(show,{progress:opts.progress}));
    }
  });
}

// Shuffle helper
function pick(arr, n, seed=0){
  const a=[...arr];let s=seed;
  for(let i=a.length-1;i>0;i--){s=(s*1664525+1013904223)&0xffffffff;const j=Math.abs(s)%(i+1);[a[i],a[j]]=[a[j],a[i]];}
  return a.slice(0,n);
}

populateRow('continue', pick(SHOWS,8,1),  {progress:true});
populateRow('top10',    pick(SHOWS,10,2), {ranked:true});
populateRow('trending', pick(SHOWS,10,3));
populateRow('new',      pick(SHOWS,6,4),  {landscape:true});
populateRow('scifi',    pick(SHOWS,10,5));
populateRow('awards',   pick(SHOWS,10,6));

// Scroll buttons
function scrollRow(id, dir){
  const row=document.getElementById(id);
  row.scrollBy({left: dir*340, behavior:'smooth'});
}

// Nav scroll effect
window.addEventListener('scroll',()=>{
  document.getElementById('nav').classList.toggle('solid', window.scrollY>60);
});

// TOAST
function toast(msg, dur=2400){
  const t=document.getElementById('toast');
  t.textContent=msg;t.classList.add('show');
  clearTimeout(t._t);t._t=setTimeout(()=>t.classList.remove('show'),dur);
}

// SEARCH
function openSearch(){
  document.getElementById('searchOverlay').classList.add('open');
  setTimeout(()=>document.getElementById('searchInput').focus(),50);
}
function closeSearchOnBg(e){
  if(e.target===document.getElementById('searchOverlay'))
    document.getElementById('searchOverlay').classList.remove('open');
}
document.addEventListener('keydown',e=>{
  if(e.key==='Escape'){
    document.getElementById('searchOverlay').classList.remove('open');
    document.getElementById('modalOverlay').classList.remove('open');
  }
});
function filterSearch(q){
  const res=document.getElementById('searchResults');
  res.innerHTML='';
  if(!q.trim()){return;}
  const hits=SHOWS.filter(s=>s.title.toLowerCase().includes(q.toLowerCase())||s.genre.toLowerCase().includes(q.toLowerCase()));
  hits.slice(0,8).forEach(s=>{
    const d=document.createElement('div');
    d.className='search-result-item';
    d.innerHTML=`<img src="${IMG_DATA[s.img]}" alt="${s.title}" loading="lazy"><span>${s.title}</span>`;
    d.onclick=()=>{document.getElementById('searchOverlay').classList.remove('open');openModal(SHOWS.indexOf(s));};
    res.appendChild(d);
  });
  if(!hits.length) res.innerHTML='<p style="color:#666;font-size:.85rem;grid-column:1/-1;padding:10px 0">No results found</p>';
}

// MODAL
function openModal(idx){
  const s=SHOWS[idx];
  document.getElementById('modalOverlay').classList.add('open');
  document.getElementById('modalHeroImg').src=IMG_DATA[s.img];
  document.getElementById('modalTitle').textContent=s.title;
  document.getElementById('modalMatch').textContent=s.match+' Match';
  document.getElementById('modalYear').textContent=s.year;
  document.getElementById('modalRating').textContent=s.rating;
  document.getElementById('modalDuration').textContent=s.dur;
  document.getElementById('modalDesc').textContent=s.desc;
  document.getElementById('modalMeta').innerHTML=
    `<div><b style="color:#777">Cast:</b> <span>${s.cast}</span></div>
     <div><b style="color:#777">Genres:</b> <span>${s.genre}</span></div>
     <div><b style="color:#777">Language:</b> <span>${s.lang}</span></div>`;
  const ml=document.getElementById('moreLike');
  ml.innerHTML='';
  const picks=pick(SHOWS.filter(x=>x!==s),6,idx*7);
  picks.slice(0,6).forEach(x=>{
    const d=document.createElement('div');
    d.className='more-card';
    d.innerHTML=`<img src="${IMG_DATA[LANDSCAPES[SHOWS.indexOf(x)%LANDSCAPES.length]]}" alt="${x.title}" loading="lazy">
      <div class="more-card-body">
        <div class="more-card-title">${x.title}</div>
        <div class="more-card-meta">${x.year} &bull; ${x.dur}</div>
        <div class="more-card-meta" style="margin-top:4px;color:#888;font-size:.7rem">${x.desc.slice(0,80)}...</div>
      </div>`;
    d.onclick=()=>openModal(SHOWS.indexOf(x));
    ml.appendChild(d);
  });
  document.getElementById('modal').scrollTop=0;
}
function closeModal(){document.getElementById('modalOverlay').classList.remove('open')}
function closeModalOnBg(e){if(e.target===document.getElementById('modalOverlay'))closeModal()}

// MY LIST
function toggleList(btn, title){
  if(myList.has(title)){myList.delete(title);btn.innerHTML='+';toast('Removed from My List')}
  else{myList.add(title);btn.innerHTML='&#10003;';toast('Added to My List')}
}
function toggleMyList(btn){
  const title=document.getElementById('modalTitle').textContent;
  if(btn.textContent.includes('+')){btn.textContent='&#10003; In My List';toast('Added to My List')}
  else{btn.innerHTML='+ My List';toast('Removed from My List')}
}

function toggleMute(btn){
  btn.innerHTML=btn.innerHTML.includes('128263')||btn.textContent==='🔇'?'&#128262;':'&#128263;';
  toast(btn.textContent==='🔇'?'Unmuted':'Muted');
}
function shareShow(){
  const t=document.getElementById('modalTitle').textContent;
  if(navigator.clipboard){navigator.clipboard.writeText('Watch '+t+' on StreamX!').then(()=>toast('Link copied to clipboard!'))}
  else toast('Share: Watch '+t+' on StreamX!');
}